对j循环进行分块，块大小设为适合L1缓存：
int jb = 32; // 根据实际缓存调整
for (jj = 0; jj < _PB_N; jj += jb)
  for (i = 0; i < _PB_M; i++)
    for (j = jj; j < min(jj+jb, _PB_N); j++)
      for (k = i+1; k < _PB_M; k++)
        B[i][j] += A[k][i] * B[k][j];

在计算前对A矩阵的部分进行转置：
// 预处理：将A的列转换为行存储
for (i = 0; i < M; i++)
  for (k = i+1; k < M; k++)
    A_trans[i][k] = A[k][i];
// 然后在循环中使用A_trans[i][k]

